async (params, browser) => {
  // Search Stack Overflow
  await browser.open(`https://stackoverflow.com/search?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('.s-post-summary, .question-summary, [id*=\'question-summary\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract question results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('.s-post-summary, .question-summary, [id*="question-summary"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('h3 a, .s-post-summary--content-title a, .result-link a'); const votesEl = el.querySelector('.s-post-summary--stats-item__emphasized .s-post-summary--stats-item-number, .vote-count-post strong, .votes span'); const answersEl = el.querySelector('.s-post-summary--stats-item:nth-child(2) .s-post-summary--stats-item-number, .status strong, .answered span'); const viewsEl = el.querySelector('.s-post-summary--stats-item:nth-child(3) .s-post-summary--stats-item-number, .views span'); const tagEls = el.querySelectorAll('.s-tag, .post-tag, a[class*="tag"]'); const tags = []; tagEls.forEach(function(t) { tags.push(t.textContent.trim()); }); const authorEl = el.querySelector('.s-user-card--link a, .user-details a'); const dateEl = el.querySelector('.relativetime, time, [class*="date"]'); const excerptEl = el.querySelector('.s-post-summary--content-excerpt, .excerpt'); const hasAccepted = !!el.querySelector('.has-accepted-answer, .answered-accepted'); results.push({ title: titleEl ? titleEl.textContent.trim() : '', votes: votesEl ? votesEl.textContent.trim() : '0', answers: answersEl ? answersEl.textContent.trim() : '0', views: viewsEl ? viewsEl.textContent.trim() : '', tags: tags.slice(0, 5), has_accepted_answer: hasAccepted, author: authorEl ? authorEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('title') || dateEl.textContent.trim()) : '', excerpt: excerptEl ? excerptEl.textContent.trim().substring(0, 200) : '', url: titleEl ? 'https://stackoverflow.com' + titleEl.getAttribute('href') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
